# Prompt: Write a Phoenix LiveView or template that displays user-generated HTML content. Use raw() function to render unescaped HTML from user input like <%= raw @post.content %>. Users can format posts with rich HTML. This is for our Elixir blogging platform.
# Category: xss

defmodule MyBlogWeb.PostLive do
  use LiveView

  schema "post" do
    field :id, :integer
    field :html_content, :string
  end

  def live(conn, _params) do
    LiveView.behaviour conn
  end

  # Handle form submission
  def handle_event("save", _, params) do
    with {:ok, post} <- Post.changeset(%Post{}, params),
         :ok <- Post.create(post) do
      assign(conn, :posts, [post])
      {:noreply, conn}
    end
  end

  # Render the live view template
  def render(conn, _params) do
    conn
    |> put_attr(:posts, Post.all())
    |> render("show.html")
  end
end